import{SimulatedAnnealing}from"./class.min.js";import{DownloadButton,GenerateButton}from"/scripts/components/buttons.min.js";import{Checkbox}from"/scripts/components/checkboxes.min.js";import{TextBox}from"/scripts/components/textBoxes.min.js";import{$}from"/scripts/src/main.min.js";export default function(){const e=new SimulatedAnnealing({canvas:$("#output-canvas")}),n=(new GenerateButton({element:$("#generate-button"),onClick:m}),new DownloadButton({element:$("#download-button"),applet:e,filename:()=>"simulated-annealing.png"}),new TextBox({element:$("#resolution-input"),name:"Resolution",value:1e3,minValue:500,maxValue:3e3,onEnter:m})),t=new TextBox({element:$("#num-nodes-input"),name:"Nodes",value:20,minValue:4,maxValue:100,onEnter:m}),o=new Checkbox({element:$("#maximum-speed-checkbox"),name:"Maximum speed"});function m(){e.run({resolution:n.value,numNodes:t.value,maximumSpeed:o.checked})}e.run({resolution:n.value,numNodes:10,maximumSpeed:!0})}